module shift_register(
    input clk,
    input rst,
    input shift_dir,
    input shift_in,
    output reg [7:0] shift_out
);

reg [7:0] reset_reg;

always @(posedge clk) begin
    if (rst)
        reset_reg <= 8'b00000000;
    else if (shift_dir)
        reset_reg <= {reset_reg[6:0], shift_in};
    else
        reset_reg <= {shift_in, reset_reg[7:1]};
end

assign shift_out = reset_reg;

endmodule
